"""
MKT Context Commentary — Acts chapter 7
Run: python3 scripts/zc-context-acts-7-7.py

Source data used:
- data/interlinear/acts.json
- data/translation/draft/mediating/acts.json (MKT text for quoting)
- data/commentary/mkt-context/acts.json (v1, v58 already present)

Key decisions in this range:
- Acts 7 is Stephen's speech — the longest speech in Acts and the most extended
  LXX survey in the NT. Context commentary focuses on what the original Jewish
  audience would have known about each OT reference, the historical traditions
  circulating in Second Temple Judaism, and the cumulative rhetorical argument.
- v14: "seventy-five" follows LXX (Gen 46:27 LXX) vs MT's 70; Stephen's text
  shows dependence on the Greek OT, which was the community Bible.
- v16: The Shechem burial conflation (Abraham bought tomb at Machpelah/Hebron
  per Gen 23; Jacob bought Shechem land per Gen 33:19) is a known exegetical
  puzzle; noted but not resolved — multiple explanations exist in scholarship.
- v22: Moses educated in Egyptian wisdom — not in Exodus but attested in Philo
  and Josephus; Second Temple tradition not a Lucan invention.
- v48: "Most High does not live in houses made by human hands" is the
  theological climax; the temple critique echoes Isa 66:1-2 and Jer 7
  (the Temple Sermon), familiar to the audience.
- v55: Jesus "standing" at the right hand (not "sitting" per Ps 110:1) may
  indicate witness/advocacy for the martyr — recognized in Jewish legal contexts
  where witnesses stand.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ACTS = {
  "7": {
    "2": "<p><strong>Theos tēs doxēs</strong> ('God of glory'): a title without exact parallel in the OT, though 'glory' language (<em>kābôd</em>/<em>doxa</em>) consistently marks YHWH's manifest presence (Exod 16:10; Ps 29:3). Stephen opens by placing Abraham's call within theophanic context — God's glory appearing — before any temple existed. <strong>en Mesopotamia</strong>: Acts specifies Mesopotamia as the site of the first theophany, before Harran. Genesis 11:31 has Terah's family leave Ur; Stephen's emphasis on Mesopotamia may reflect Gen 15:7 ('I am YHWH who brought you out of Ur of the Chaldeans') or LXX tradition. The point is that God's self-revealing to Israel began outside the promised land, in a pagan context — the pattern that runs through the whole speech.</p>",

    "3": "<p>The citation of Gen 12:1 ('Leave your country and your people') follows the LXX wording — <em>ek tēs gēs sou kai ek tēs syngenias sou</em>. The command is unconditional: no destination is named, only the assurance 'the land I will show you.' This pattern — God commanding departure without specifying arrival — is the structural template Stephen applies to Moses (v.34) and implicitly to the disciples: obedient departure in response to divine call, destination unknown to the human recipient. The audience of the speech would have heard this as paradigmatic of faithful response to God's word.</p>",

    "4": "<p><strong>After the death of his father</strong>: a chronological detail that creates tension with the MT of Genesis. Genesis 11:26 gives Terah's age as 70 when Abraham was born; Gen 11:32 puts Terah's death at 205. If Abraham left Harran at 75 (Gen 12:4), Terah would have been 145 — not yet dead by 60 years. The LXX tradition resolves this: some witnesses read Terah's death at 145 rather than 205. The Samaritan Pentateuch similarly places Terah's death before Abraham's departure. Stephen follows a textual tradition that harmonized the timeline; this is a text-critical datum, not a careless error, and his audience likely knew the harmonizing tradition.</p>",

    "5": "<p><strong>Oudé bēma podos</strong> ('not even a foot of ground'): the phrase echoes Deut 2:5, where Israel receives 'not so much as a footstep's worth of land' from Edom. Applied to Abraham, it highlights the covenant paradox: God promises a land while giving Abraham none of it during his lifetime. The patriarchal promise was believed on word alone — the land held in hope without possession. Hebrews 11:8-16 celebrates precisely this faith; Stephen's speech draws on the same tradition of land-as-promise rather than land-as-possession. <em>Kata kataschein</em> (for an inheritance): the LXX vocabulary of land-grant (Num 26:53-55), signaling the covenantal register.</p>",

    "6": "<p><strong>Tetrakosi etē</strong> ('four hundred years'): follows Gen 15:13 LXX, where God reveals the future at the formal covenant ceremony. Exod 12:40 gives 430 years, counting from a different starting point. Both are traditional rounded figures: the 400 counts from the promise to Abraham; the 430 from Israel's entry into Egypt. Paul uses 430 years in Gal 3:17 for a different argument. The covenant-making context of Gen 15 matters here — God reveals the slavery-and-exodus pattern within the covenant-ratification ritual, indicating that even the suffering of the Egypt period was within the covenant frame, not outside it.</p>",

    "7": "<p><strong>En tō topō toutō</strong> ('in this place'): the divine promise blends Gen 15:14 ('they will come out with great possessions') with Exod 3:12 ('you will worship God on this mountain'). The 'this place' of Gen 15 contextually means Canaan; applied to Exod 3, it means Sinai/Horeb. Stephen appears to exploit this ambiguity deliberately — God's promised place of worship was Sinai before it was Jerusalem, and a land before it was a temple. The blending of texts anticipates his argument in v.48 that God's presence is not fixed to any human structure.</p>",

    "8": "<p><strong>Diathēkēn peritomēs</strong> ('covenant of circumcision'): the formal covenant of Gen 17, where circumcision seals the body as the covenant sign. The eight-day timing (Gen 17:12; 21:4) distinguishes Israelite infant circumcision from adult initiation rites in surrounding cultures. Stephen's rhetorical structure: he names the circumcision covenant here, then accuses his audience of 'uncircumcised hearts and ears' (v.51) — they possess the bodily sign but not its heart-reality (Deut 10:16; Jer 4:4; 9:26). The twelve patriarchs' list closes the genealogical bracket and opens the Joseph section, which is the first of three rejection-and-vindication cycles.</p>",

    "9": "<p><strong>Zēlōsantes</strong> ('jealous'): the Joseph story (Gen 37-50) circulated in expanded forms in Second Temple Judaism — Josephus (<em>Ant.</em> 2.1-10) and the <em>Testament of Joseph</em> elaborate it substantially. The jealousy term (<em>zēloō</em>) is the same root as the zeal that drove Saul of Tarsus (8:1-3); the irony is available to any audience that has read Acts to this point. <em>Ho theos ēn met' autou</em> ('God was with him'): the refrain throughout the Joseph narrative (Gen 39:2, 21, 23) is the theological key to Joseph's reversals — human rejection met by divine accompaniment. This phrase is the capsule of Stephen's argument: human rejection of God's chosen does not undo divine election.</p>",

    "10": "<p><strong>Charin enantion Pharaō</strong> ('grace/favor before Pharaoh'): the LXX vocabulary of <em>charis</em> (favor) before a superior is standard court language of the patronage system. Joseph's rise from slave to second-in-command (Gen 41:40-44) is the OT's most dramatic status-reversal — the sold slave rules over his sellers. Josephus (<em>Ant.</em> 2.9.1) and Philo (<em>De Josepho</em>) developed Joseph's wisdom as a Hellenistic philosophical virtue, making him a Jewish culture-hero; Stephen's mention of 'wisdom' draws on this tradition even if not explicitly citing it.</p>",

    "11": "<p><strong>Thlipsis megalē</strong> ('great suffering'): the famine in Gen 41:54-57 is depicted as universal — 'all the earth' had no grain. The word <em>thlipsis</em> (distress, tribulation) connects the Joseph narrative to the biblical pattern of tribulation preceding vindication — the same pattern Stephen traces through Moses and applies implicitly to the church's persecution. The entire Joseph section demonstrates that God's purposes advance through, not despite, the suffering of the rejected.</p>",

    "12": "<p><strong>Sitia</strong> ('grain/food'): Jacob hears of grain in Egypt through rumor — ordinary human report, not divine revelation. The contrast between Jacob's dependence on secondhand information and God's providential arrangement of Joseph's presence beforehand is the narrative's theological point. Providence operates beneath the surface of apparently ordinary human decisions — exactly the pattern Stephen will apply to Moses's rejection and vindication, and implicitly to the apostles' situation in Jerusalem.</p>",

    "13": "<p><strong>En tē deutera</strong> ('on the second visit'): Genesis 43-45 narrates the second trip to Egypt, culminating in the revelation scene (Gen 45:1-4) — one of the most emotionally charged moments in the Pentateuch. Joseph's weeping and self-disclosure — 'I am Joseph your brother, whom you sold into Egypt' (Gen 45:4) — is a moment of total reversal: the dead-to-them brother stands alive as their ruler. Stephen's compression (v.13) names the self-disclosure without dwelling on it; the rhetorical point is that recognition was delayed, not immediate, and came only after multiple rejections. The pattern: rejected → exalted → returns to reveal himself to those who rejected him.</p>",

    "14": "<p><strong>Hebdomēkonta pente psychas</strong> ('seventy-five persons'): the MT of Gen 46:27 and Deut 10:22 gives 70; the LXX of Gen 46:27 gives 75 by including Joseph's grandsons (Manasseh's and Ephraim's sons, not in the MT list). Stephen follows the LXX number — confirming that the Greek OT is his and his audience's Bible. This is not a historical discrepancy but a text-critical datum: the Diaspora community read the Septuagint, and its figure was 75. The LXX's expanded number reflects a counting tradition that adds additional descendants; both figures count 'those who went down to Egypt' but apply different inclusion criteria.</p>",

    "15": "<p><strong>Katebē Iakōb eis Aigupton</strong> ('Jacob went down to Egypt'): 'going down' to Egypt and 'going up' from Egypt is a consistent theological geography in the OT — Egypt is always spatially and symbolically 'below,' Canaan-Jerusalem 'above.' Jacob's descent was driven by famine, enabled by Joseph's position. The brevity of 'he and our ancestors died' anticipates v.16's burial note. Death in foreign soil — outside the promised land — was a theological anomaly requiring resolution: their bodies needed to return to the promised land, just as God's people would ultimately need to return from exile.</p>",

    "16": "<p><strong>Eis Sychem</strong> ('to Shechem'): one of the most studied textual difficulties in Acts. Genesis 23 records Abraham purchasing a tomb at Machpelah near Hebron from Ephron the Hittite; Joshua 24:32 records Joseph's burial at Shechem in the plot Jacob purchased from the sons of Hamor (Gen 33:19). Stephen appears to combine both transactions, attributing the Shechem purchase to Abraham rather than Jacob. Ancient solutions include: (a) a lost tradition of Abraham also buying land at Shechem; (b) scribal conflation in the speech tradition; (c) a summary that attributes the entire patriarchal land-purchase history to the period generally. Luke records Stephen's speech as delivered, not corrected; the difficulty belongs to the speech tradition, not Luke's editorial process.</p>",

    "17": "<p><strong>Ēngizen ho chronos tēs epangelias</strong> ('the time of the promise drew near'): divine timing language — God's promises operating on a schedule invisible to the recipients but recognizable in retrospect — is characteristic of Luke-Acts throughout (cf. Luke 1:20; Acts 1:6-7; Gal 4:4). The population growth (<em>ēuxēsen ho laos</em>) echoes Exod 1:7-12, itself echoing Gen 1:28 ('be fruitful and multiply'). Increase of God's people is a covenant-fulfillment sign; Pharaoh's suppression of it is the counter-movement that the exodus will reverse. The 'drawing near' of the promise's fulfillment increases the pressure on both sides.</p>",

    "18": "<p><strong>Basileùs heteros</strong> ('a different king'): citing Exod 1:8 LXX — 'a new king arose over Egypt who did not know Joseph.' In Second Temple interpretation, the 'not knowing Joseph' was understood as willful political amnesia — the new dynasty suppressed memory of Joseph's administration because acknowledging dependence on a Hebrew slave was politically inconvenient. Josephus (<em>Ant.</em> 2.9.1) connects the change to an ethnic succession. The theological point is that human political power forgets God's prior acts of provision; the structural point is that the pattern of rejection-amnesia is endemic — it recurs at each generation's turning point.</p>",

    "19": "<p><strong>Ektithesthai ta brephē autōn</strong> ('to expose/throw out their newborn babies'): the Greek verb <em>ektithēmi</em> is the technical term for infant exposure — a common Greco-Roman practice in which unwanted infants were left in public places to die or be collected by slave traders. The Hebrew practice Stephen describes (Exod 1:22, throwing male infants into the Nile) is the Pharaonic decree. Stephen uses Hellenistic vocabulary to describe a Semitic practice, making it comprehensible to his bilingual audience. The explicit purpose — 'so that they would die' (<em>eis to mē zōogoneisthai</em>) — strips away any euphemism from Pharaoh's policy.</p>",

    "20": "<p><strong>Asteios tō theō</strong> ('beautiful/pleasing to God'): translates Exod 2:2's Hebrew <em>tôb</em> ('good/beautiful child') with the intensifier <em>tō theō</em> ('to God'). Philo (<em>De Vita Mosis</em> 1.2-9) develops Moses's extraordinary beauty and gifts in detail, connecting them to divine calling. Heb 11:23 uses the same Greek phrase. The three-month concealment (Exod 2:2) was an act of civil disobedience against Pharaoh's decree — a repeated pattern in the exodus story where the vulnerable (midwives, Moses's mother) resist imperial power through quiet non-compliance.</p>",

    "21": "<p><strong>Thugatēr Pharaō</strong> ('Pharaoh's daughter'): Exodus 2:5-10 gives no name; Josephus (<em>Ant.</em> 2.9.5) names her Thermouthis. She adopts Moses formally (<em>anethrefsato heautē eis huion</em>, 'brought him up as her own son') — in Egyptian royal court context this gave Moses the legal status and education of royalty. The adoption bridges the paradox of Moses's identity: biologically Hebrew, legally Egyptian, called by God as Israel's deliverer. The irony that the instrument of Israel's liberation is trained in the household of Israel's oppressor is one of Stephen's key structural points: God uses the world's own structures to accomplish what the world opposes.</p>",

    "22": "<p><strong>Epaideuthe Mōysēs pasē sophia Aigyptōn</strong> ('Moses was educated in all the wisdom of the Egyptians'): not stated in Exod 2, which moves directly from adoption to adulthood; this is a tradition attested in Philo (<em>De Vita Mosis</em> 1.5-23 — philosophy, arithmetic, geometry, music) and Josephus (<em>Ant.</em> 2.9.7 — military leadership). The 'wisdom of the Egyptians' included hieroglyphic writing, astronomical knowledge, and administrative expertise. This tradition explained how a former slave's grandson could function as a royal court negotiator; it was also part of Jewish apologetics showing that Moses surpassed pagan wisdom-traditions — not inferior to Greek philosophy.</p>",

    "23": "<p><strong>Plēroumenō tesserakontaetēs chronos</strong> ('when he was forty years old'): the three-part structure of Moses's life as three 40-year periods (40 in Egypt, 40 in Midian, 40 in wilderness) is not stated in the biblical narrative but is a standard Second Temple interpretive framework. Philo, Josephus, and the rabbis all use it. The 40-year period is the biblical number for a generation of probation (40 years in the wilderness = one generation). Stephen's use of the three-period structure shows his dependence on this interpretive tradition; his audience would have recognized it immediately.</p>",

    "24": "<p><strong>Ēmynato tō kataponoumenō</strong> ('he went to his defense, helped the oppressed one'): Stephen characterizes Moses's killing of the Egyptian (Exod 2:12) as <em>ekdikēsis</em> (advocacy/defense) on behalf of the oppressed — a legitimizing interpretation. The LXX of Exod 2:12 simply says 'he killed the Egyptian'; Stephen interprets the act as juridical advocacy for the vulnerable. This is consistent with a legal reading: Moses as judge (explicitly his assigned role in v.27) administering justice to a vulnerable Israelite. The contrast between Moses's advocacy and Israel's rejection of it (v.27) is the central irony of the episode — the deliverer is rejected by those he delivers.</p>",

    "25": "<p><strong>Enomizan synienai</strong> ('he supposed they would understand'): this psychological motivation is absent from Exodus. Exod 2:12-13 gives no indication of Moses's reasoning; Stephen adds it. This is a significant hermeneutical move — it transforms Moses's act from individual vigilante violence into a failed attempt at public ministry. The failure to understand (<em>ou synēkan</em>) anticipates the reception of Jesus in Luke 19:44 ('you did not recognize the time of your visitation') and the parable of the wicked tenants (Luke 20:9-16). The pattern of people failing to recognize their own deliverer is Stephen's organizing theme.</p>",

    "26": "<p><strong>Synēllasen eis eirēnēn</strong> ('tried to reconcile them'): <em>synallassō</em> (reconcile, bring together) is legal and diplomatic vocabulary — Moses attempts to mediate a dispute between parties who are in the wrong. The scene (Exod 2:13-14) shows Moses intervening as a would-be judge/arbitrator. The irony Stephen's audience is meant to catch: the man who will formally adjudicate disputes for millions (Exod 18:13-26) is here unable to resolve a conflict between two countrymen. The rejection of small-scale mediation anticipates the rejection of Moses as national deliverer.</p>",

    "27": "<p><strong>Tis se katestēsen archonta kai dikastēn</strong> ('who made you ruler and judge over us?'): the question from Exod 2:14 LXX is cited twice in Stephen's speech (here and v.35), becoming the paradigmatic instance of Israel rejecting God's appointed deliverer. The double citation is rhetorical — repetition drives home the structural parallel with Jesus's rejection. In OT legal context, the question is technically valid: authority as 'ruler and judge' (<em>archōn kai dikastēs</em>) required formal appointment. Moses had no such appointment yet. But the questioner, while technically correct, was spiritually blind to who Moses was and why he acted.</p>",

    "28": "<p>The exposure of Moses's killing — 'Are you thinking of killing me as you killed the Egyptian yesterday?' — is the moment of his legal vulnerability: he had committed manslaughter outside any judicial structure, without the Torah's provisions for distinguishing premeditated from accidental killing (not yet given). Moses's exposure by a fellow Hebrew is the ultimate irony: the one he defended becomes the instrument of his flight. <em>Echthes</em> ('yesterday') signals the brevity between act and accusation — a compressed crisis that mirrors the speed of the Sanhedrin's response to Stephen's speech.</p>",

    "29": "<p><strong>Paroikos en gē Madiam</strong> ('resident alien in the land of Midian'): <em>paroikos</em> (sojourner, resident alien) is the LXX term for a person living in a land not their own without full civic rights — the same condition as Israel in Egypt (v.6). Moses becomes what his people were: a foreigner without standing. He names his son Gershom (Exod 2:22, <em>gēr shom</em> = 'a sojourner there'), encoding his alien status in the child's name. The Midianites were descendants of Abraham through Keturah (Gen 25:2), so Moses's refuge was in kinship territory, not entirely foreign — a detail his audience would know and that mitigates the sense of total estrangement.</p>",

    "30": "<p><strong>En tē erēmō tou orous Sina</strong> ('in the desert of Mount Sinai'): Stephen uses Sinai rather than Horeb (the name used in Exod 3:1; Deut consistently uses Horeb). Sinai and Horeb are two names for the same sacred mountain; LXX uses Sinai more often in Exodus. The forty years in Midian completes the second of three 40-year periods. The burning bush — fire in a bush that does not consume — was visually and conceptually the opposite of the ordinary: normal fire destroys vegetation; this fire sustained and illuminated it. The paradox of the burning-but-unburned bush signals the supernatural quality of the theophany before God speaks.</p>",

    "31": "<p><strong>Thaumazōn to horama</strong> ('marveling at the sight'): Moses approaches to investigate (Exod 3:3) — the natural curiosity of an alert shepherd. The approach triggers divine address: God speaks when the human draws near. This pattern — divine address requiring prior human attention — recurs throughout OT theophany (Abraham in Gen 22; Samuel in 1 Sam 3; Elijah in 1 Kgs 19). <em>Phonē kyriou egeneto</em> ('the voice of the Lord came'): the LXX vocabulary for prophetic reception, marking Moses's experience as continuous with the prophetic tradition — not a private mystical experience but a commission parallel to Isaiah's (Isa 6) and Jeremiah's (Jer 1).</p>",

    "32": "<p><strong>Egō ho theos tōn paterōn sou</strong> ('I am the God of your fathers'): the triple name — Abraham, Isaac, Jacob — is the formal covenant identification that grounds all subsequent appeals to the covenant promises (Exod 3:6). Moses 'trembled and did not dare to look' (<em>entromos genomenos ouk etolma katanoeō</em>): trembling before divine presence is a standard theophanic response (Dan 8:17; Ezek 1:28; Rev 1:17). The contrast between Moses's reverent fear and the Sanhedrin's reaction (v.54, grinding teeth) is a structural irony available to Stephen's audience: those who should tremble do not; Moses, the deliverer, did.</p>",

    "33": "<p><strong>Lyson to hypodēma tōn podōn sou</strong> ('take off your sandals'): removing sandals before holy ground was practiced across the ancient Near East — not uniquely Israelite. It appears in Jewish, Egyptian, and Babylonian contexts as a mark of reverence before sacred space. The rabbinic prohibition against wearing sandals in the temple courts derived from this principle. <em>Hē hagia</em> (holy ground): the sanctification of ground by divine presence — at Sinai, without a constructed building — is precisely the point Stephen is building toward in v.48. Sinai is holy because God is present there; no human structure created that holiness.</p>",

    "34": "<p><strong>Idōn eidon tēn kakōsin</strong> ('I have indeed seen the oppression'): the cognate absolute (<em>idōn eidon</em>) follows the Hebrew infinitive absolute construction, intensifying the verb — 'I have certainly/truly seen.' This is LXX Exod 3:7. The divine 'coming down' (<em>katebēn</em>) is an anthropomorphism for direct intervention (cf. Gen 11:5, God 'comes down' to see Babel). The commissioning formula — 'Now come, I will send you back to Egypt' — repeats the pattern of divine call to return to the place of danger, the pattern of Abraham's call, the prophets' calls to hostile audiences, and the disciples' mission to the nations.</p>",

    "35": "<p><strong>Touton ton Mōysēn hon ērnounto</strong> ('this same Moses whom they refused'): the demonstrative <em>touton</em> ('this one') repeats three times in vv.35-38, marking each statement as a typological pivot. The combination of <em>archōn</em> (ruler) and <em>lytrotēs</em> (deliverer/redeemer) is significant: <em>lytrotēs</em> is a NT hapax, but the related <em>lytrōsis</em> (redemption) and <em>lytrōtēs</em> link to Isaianic new-exodus vocabulary (Luke 1:68; 2:38; 24:21). 'Through the angel' reflects the Second Temple tradition of angelic mediation in theophanies — a tradition that elevated theophanies rather than diminishing them, situating them within the cosmic order of divine messengers.</p>",

    "36": "<p><strong>Terata kai sēmeia</strong> ('wonders and signs'): the paired terms are the LXX vocabulary for the plague-signs of Egypt (Exod 7-12; Deut 4:34; 6:22). The sequence — Egypt, Red Sea (<em>en Erythrō thalassē</em>), wilderness (40 years) — matches the Deuteronomic summary (Deut 1:1-3; Josh 24:5-7). Stephen compresses 40 years into one verse, assuming audience knowledge; the point is the sustained series of divine acts accomplished through Moses over his entire 40-year ministry. The summary validates Moses as the paradigmatic prophet-deliverer whose works authenticate divine mandate.</p>",

    "37": "<p><strong>Prophētēn hymīn anastēsei ho theos ... hōs eme</strong> ('God will raise up a prophet like me'): Deut 18:15-19 was a crucial messianic text in Second Temple Judaism. The Qumran community (4QTest, 4QFlor) applied it to an eschatological prophetic figure. Peter applied it to Jesus in Acts 3:22-23. Stephen's inclusion in Moses's own speech places the prophecy within the Pentateuchal narrative itself — Moses predicts his own succession by a greater prophet. The implicit argument: if Israel's paradigmatic sin was rejecting Moses, rejecting the prophet-like-Moses (Jesus) is the ultimate expression of the same pattern.</p>",

    "38": "<p><strong>En tē ekklēsia en tē erēmō</strong> ('in the assembly/congregation in the wilderness'): <em>ekklēsia</em> is the LXX translation of Hebrew <em>qāhāl</em> (assembly/congregation) — the same word used for the early Christian community. Its use here connects the Sinai community to the NT <em>ekklēsia</em>: the same word, the same structure of covenant assembly. The 'angel who spoke to him on Mount Sinai' reflects the Jewish tradition of angelic mediation at Sinai (Gal 3:19; Heb 2:2; Josephus <em>Ant.</em> 15.5.3). <em>Logia zōnta</em> ('living words/oracles'): Torah as divine speech — the same characterization as Heb 4:12 ('the word of God is living and active'). Torah is not static text but active communication.</p>",

    "39": "<p><strong>Hō ouk ēthelēsan hypakooi genesthai</strong> ('they were not willing to obey him'): the aorist <em>ēthelēsan</em> signals a decisive volitional refusal — not inability but unwillingness. <em>En tais kardiais autōn estrapsēn eis Aigupton</em> ('in their hearts they turned back to Egypt'): the internal orientation toward Egypt precedes the external apostasy of the golden calf. Deuteronomy's ethical reinterpretation of the wilderness generation's failures (Deut 29-30) moved from external covenant-breaking to heart-apostasy — the same move Stephen makes in connecting the golden calf to 'uncircumcised hearts' (v.51).</p>",

    "40": "<p><strong>Poiēson hēmin theous</strong> ('make us gods who will go before us'): the citation of Exod 32:1 LXX is exact. The demand for gods 'who will go before us' (<em>hoi proporeusontai hēmōn</em>) reflects the function of the ark and pillar of cloud/fire — mobile divine presence leading the march. The golden calf was not necessarily intended as a different deity but as a visible representation of YHWH's presence — the same category of error as confusing a human-made representation with divine reality. <em>Ho Mōysēs houtos</em> ('this Moses'): the dismissive <em>houtos</em> from Exod 32:1 echoes the dismissive question of v.27 — Israel's first rejection of Moses prefigures the golden calf apostasy.</p>",

    "41": "<p><strong>Emoskhopoiēsan</strong> ('they made a calf'): a compound verb created for this passage; the underlying Hebrew is <em>ʿēgel massēkāh</em> ('molten calf'). The celebration with sacrifices (<em>thysia</em>) and 'reveling' (<em>euphraínesthai en tois ergois tōn cheirōn autōn</em>, 'rejoicing in the works of their hands') is the standard prophetic condemnation of idol-worship (Isa 2:8; Hos 14:3; Jer 1:16). 'Works of their hands' is the prophetic tag for idols — human manufacture mistaken for divine presence. Stephen has moved from narrative to prophetic indictment mode, the tone that will carry through to v.53.</p>",

    "42": "<p><strong>Estrepsen de ho theos kai paredōken autous</strong> ('God turned and gave them over'): the judicial abandonment pattern Paul will elaborate in Romans 1:24, 26, 28 — three times 'God gave them over' to their chosen sins. Here the giving-over is to star worship, following the golden calf. The LXX of Amos 5:25-27 that Stephen quotes differs from the MT: MT has 'Sikkuth your king and Kiyyun your star-god'; LXX/Stephen have 'the tabernacle of Moloch and the star of the god Rephan.' The astrological deities condemned by Amos were celestial powers — Moloch/Saturn, Rephan/Saturn in Egyptian-Aramaic — whose worship Stephen identifies as the consequence of turning from the invisible God to visible representations.</p>",

    "43": "<p><strong>Meteikiō hymas epekeina Babylōnos</strong> ('I will exile you beyond Babylon'): the Amos 5:27 MT has 'beyond Damascus'; Stephen/LXX has 'beyond Babylon,' updating the geographic reference to the Babylonian exile that later proved more catastrophic. This reflects either a deliberate interpretive update (the final exile reached Babylon and beyond) or the LXX textual tradition. The point for Stephen's argument: the temple worship his audience is defending was preceded by centuries of idolatry that God judged with exile — the temple is not an unconditional guarantee of divine favor.</p>",

    "44": "<p><strong>Hē skēnē tou martyriou</strong> ('tabernacle of testimony/witness'): called the 'tabernacle of testimony' because it housed the covenant tablets — the <em>edut</em> (testimony/covenant document). <em>Kata ton typon hon heōrakei</em> ('according to the pattern he had seen'): Exod 25:40, cited again in Heb 8:5. The 'pattern' (<em>typos</em>) Moses saw — the heavenly archetype — means the earthly tabernacle was a copy of a heavenly reality. This Platonic-sounding language (visible thing copied from invisible archetype) was at home in Alexandrian Jewish interpretation; Stephen may draw on Alexandrian traditions even while speaking in Jerusalem. The tabernacle's status as copy means God's true dwelling is not on earth.</p>",

    "45": "<p><strong>En tē kataschesei tōn ethnōn</strong> ('when they took possession from the nations'): the Canaanites were displaced in the conquest; the tabernacle was brought in and placed at Shiloh (Josh 18:1), later at Nob and Gibeon. The portable sanctuary served Israel for centuries throughout the conquest and judges periods — without a permanent building, without any apparent deficiency. Stephen's point: the portable tabernacle 'worked' perfectly well for centuries. The pressure toward a permanent structure came from the human side (David's desire, v.46; Solomon's building, v.47), not from any divine necessity.</p>",

    "46": "<p><strong>Aitēsato eurein skēnōma</strong> ('asked that he might find a dwelling place'): a text-critical decision affects the argument here. The variant 'for the house of Jacob' (<em>tō oikō Iakōb</em>) is attested in important early manuscripts against the more common 'for the God of Jacob' (<em>tō theō Iakōb</em>). The 'house of Jacob' reading shifts meaning: David sought not to build a house for God but a dwelling for Jacob's people — which God gave them in the land, not in a temple. This aligns with Nathan's oracle in 2 Sam 7:5-7, where God explicitly says he has not asked for a cedar house from anyone. David's desire to build was not authorized by God — God authorized a later successor's building.</p>",

    "47": "<p><strong>Salōmōn de ōkodomēsen autō oikon</strong> ('but it was Solomon who built a house for him'): the adversative <em>de</em> ('but') is mild but pointed. Solomon, not David, built it — the building was a concession granted after God's explicit statement that he does not need a house (2 Sam 7:5-7). In rabbinic tradition the reason for David's exclusion is debated: his wars and bloodshed made him unfit (1 Chr 22:8). Stephen does not dwell on this; his point is to place the Solomonic temple in the narrative sequence after centuries of portable tabernacle worship, marking it as a later development rather than an eternal divine requirement.</p>",

    "48": "<p><strong>Ouch ho Hypsistos en cheiropoiētois katoikei</strong> ('the Most High does not live in things made by human hands'): <em>Hypsistos</em> ('Most High') is a title used for YHWH in LXX but also for Zeus in the Hellenistic world — a term with ecumenical resonance. <em>Cheiropoiētos</em> ('hand-made') is the LXX word for idols (Lev 26:1; Isa 2:18; 16:12). Its application to the Jerusalem temple is the speech's climactic provocation: the temple Stephen's accusers are defending is labeled with the same word used for idols throughout the LXX. The Isaiah 66:1-2 citation that follows provides the prophetic warrant — this is not Stephen's innovation but Isaiah's.</p>",

    "49": "<p><strong>Ho ouranos moi thronos, hē de gē hypopodion</strong> ('heaven is my throne, earth is my footstool'): Isaiah 66:1 LXX, opening the book's final oracle. The spatial logic demolishes the premise of temple-building: God's throne is the heavens — no building of any size could contain him. Isaiah 66 continues with a vision of universal worship (66:18-21, 'I will gather all nations and peoples'), which Stephen does not quote but which is available to his audience as background. <em>Hypopodion</em> (footstool): the entire earth is God's footstool — smaller than his throne. The term was also used for the ark and temple in OT tradition (Ps 99:5; 132:7), ironically subsumed here under the cosmic image.</p>",

    "50": "<p><strong>Ouchi hē cheir mou epoiēsen tauta panta</strong> ('has not my hand made all these things?'): the rhetorical question closes the Isaianic citation. The 'hand of God' that made all things is contrasted with <em>cheiropoiēta</em> (things made by human hands, v.48). Creation is God's work; the temple is human work. This is not a rejection of temple worship per se — Isaiah 66 does not abolish worship — but a corrective to the theology that treats the temple as guaranteeing divine presence regardless of Israel's obedience. Jeremiah's temple sermon (Jer 7:4) made the same point: 'Do not trust in these deceptive words: This is the temple of the LORD, the temple of the LORD, the temple of the LORD.'</p>",

    "51": "<p><strong>Sklērotrachēloi kai aperitmētoi kardiais kai tois ōsin</strong> ('stiff-necked and uncircumcised in hearts and ears'): two OT accusations combined. 'Stiff-necked' (<em>sklērotrachēlos</em>) is Exod 33:5 and Deut 9:6, 13 — Israel's characterization during the wilderness period, the very period Stephen has been narrating. 'Uncircumcised hearts' is Jer 4:4; 9:26; Lev 26:41; Deut 10:16 — the prophetic reinterpretation of circumcision as heart-condition rather than physical rite. 'Uncircumcised ears' recalls Jer 6:10. The circumcision they bodily possess (the covenant sign of v.8) is contradicted by uncircumcised hearts and ears. Stephen charges his audience with the exact spiritual condition that produced every failure he has narrated.</p>",

    "52": "<p><strong>Tina tōn prophētōn ouk ediōxan hoi pateres hymōn</strong> ('which of the prophets did your fathers not persecute?'): a recognized Second Temple Jewish motif — the 'Deuteronomistic' pattern of prophet-persecution by the covenant people. The <em>Lives of the Prophets</em> (first century CE) catalogs violent deaths: Isaiah sawn in two, Amos beaten to death, Micah thrown off a cliff, Habakkuk stoned. Jesus's own lament (Luke 13:34 — 'Jerusalem, Jerusalem, who kills the prophets') drew on this tradition. <em>Ton Dikaion</em> ('the Righteous One'): the messianic title used in Acts 3:14 (Peter) — rooted in Isa 53:11 ('the Righteous One, my servant, will justify many') and the <em>Book of Enoch</em>'s 'righteous one' for the Son of Man.</p>",

    "53": "<p><strong>Eis diatagēn angelōn</strong> ('at the ordinance/direction of angels'): the tradition of angelic mediation at Sinai is attested in multiple sources: Deut 33:2 LXX ('his angels with him'); Gal 3:19 ('ordained through angels'); Heb 2:2 ('the message declared by angels'); Josephus <em>Ant.</em> 15.5.3. In Jewish theology this elevated the Torah's authority — divine origin through the highest conceivable mediators. Stephen turns it into the sharpest possible indictment: the more exalted the source, the more inexcusable the disobedience. A law mediated through angels — above any prophet, any king, any human authority — was not kept. The accusation closes the historical survey and opens the verdict.</p>",

    "54": "<p><strong>Dieprionto tais kardiais autōn</strong> ('they were furious, cut to the heart'): <em>diapriō</em> literally means 'to saw through/cut apart' — the speech cut through the audience's composure. The same word appears in Acts 5:33 (the Sanhedrin's reaction to Peter and the apostles) — a Lukan verbal echo connecting the two scenes. The gnashing of teeth (<em>ebrychon tous odontas</em>) is the imagery of wild animals baring teeth at prey (Ps 35:16; 37:12 LXX) and in the NT is associated with final judgment (Matt 8:12; 13:42, 50; 22:13; 25:30; Luke 13:28). The Sanhedrin enacts the eschatological judgment-response toward the one who has spoken God's word — another of Stephen's ironic reversals.</p>",

    "55": "<p><strong>Iēsoun hestōta ek dexiōn tou theou</strong> ('Jesus standing at the right hand of God'): Psalm 110:1 has the LORD say 'Sit at my right hand' — consistently applied to the exalted Christ in the NT (Acts 2:34; Heb 1:3; 8:1). But here Jesus is <em>standing</em>, not sitting. Several Second Temple Jewish texts describe heavenly beings as standing in the divine council (1 Enoch 40:2; 2 Enoch 21:3). The standing posture may indicate: (a) Jesus as witness-advocate for Stephen before the heavenly court — witnesses stand to testify in Jewish legal contexts; (b) Jesus rising to receive the martyr; (c) the 'Son of Man' approaching the Ancient of Days (Dan 7:13). The vision is the only NT occurrence of Jesus 'standing' at the right hand, and Stephen is the only one who sees it.</p>",

    "56": "<p><strong>Ton huion tou anthrōpou ek dexiōn hestōta tou theou</strong> ('the Son of Man standing at the right hand of God'): the title 'Son of Man' — Jesus's characteristic self-designation in the Gospels (81 occurrences) — here is the only NT use by someone other than Jesus himself (outside the Gospels; cf. Rev 1:13; 14:14, 'one like a son of man'). Stephen's vision uses Dan 7:13-14 vocabulary ('son of man coming with the clouds of heaven'). The 'open heaven' (<em>diēnoigmenous tous ouranous</em>) frames the vision as prophetic theophany — the opened heaven is the standard mark of vision-reception in Ezekiel (1:1), the baptism accounts (Mark 1:10), and Revelation (4:1). Heaven's opening confirms the word spoken.</p>",

    "57": "<p><strong>Syneschon ta ōta autōn</strong> ('they covered their ears'): a theatrical expression of refusal to hear blasphemy — physically closing the ears cut off the offending words from being processed. The high priest tearing his robes at Jesus's trial (Mark 14:63-64) and this ear-covering gesture are parallel ritual expressions of official outrage at claimed blasphemy. <em>Hōrmēsan homothymadon ep' auton</em> ('they all rushed upon him together'): <em>homothymadon</em> ('with one accord') is used earlier in Acts for the unified action of the prayer community (1:14; 2:46; 4:24); here it describes the mob action of rejection — the same word, two contrasting communities.</p>",

    "59": "<p><strong>Kyrie Iēsou, dexai to pneuma mou</strong> ('Lord Jesus, receive my spirit'): the parallel to Jesus's last word on the cross is exact: Jesus prays Ps 31:5 ('Father, into your hands I commit my spirit,' Luke 23:46). Stephen substitutes 'Lord Jesus' for 'Father' — addressing the risen, exalted Jesus with the prayer Jesus addressed to the Father. This is either an implicit statement of Jesus's divine status or the natural expression of a vision in which Jesus is visible. The martyrological formula ('receive my spirit') became a pattern in Christian martyr tradition, appearing in later martyrdom accounts (Polycarp, Ignatius). Stephen's death establishes the template for Christian martyrdom.</p>",

    "60": "<p><strong>Kyrie, mē stēsēs autois tēn hamartian tautēn</strong> ('Lord, do not charge this sin against them'): the parallel to Jesus's prayer of forgiveness from the cross (Luke 23:34 — 'Father, forgive them, for they do not know what they are doing') is unmistakable. The use of 'Lord' in the context of v.59's 'Lord Jesus' suggests the prayer is again addressed to Jesus. <em>Mē stēsēs</em> (lit. 'do not stand/set against them') is a legal idiom — do not put this on their account. The forgiveness prayer immediately before death frames Stephen's death as not only mirroring Christ's death in its pattern but extending Christ's own forgiving prayer. The young man Saul witnessed both the dying prayer and the face 'like an angel' (6:15) — details Luke places in the narrative to frame Paul's later conversion.</p>"
  }
}

